# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from os import path

class FileAccessControlSystem():
    def __init__(self, db_name="permission.db", file_path = "sample.txt"):
        self.conn = sqlite3.connect(db_name)  # Connect to the permission database
        self.cursor = self.conn.cursor()
        self.file_path = path.abspath(file_path)  # Get absolute path of file
        
    def check_permission(self, username):
        """Check if user has permission"""
        query = f"SELECT * FROM permissions WHERE username='{username}' AND file='{self.file_path}'"
        result = self.cursor.execute(query).fetchone()  # Execute the SQL command and fetch one row  
        
        if result is not None:
            permission, _, _ = result
            
            if permission == 'read':
                return True

        return False   
    
    def open_file(self, username):
        """Open file if user has permissions"""
        if self.check_permission(username):   # Check for read access
            
            try: 
                with open(self.file_path) as f:
                    content = f.read()   # Read the contents of the file
                    
                return content   
                
            except FileNotFoundError:  # If file is not found, print a helpful message and return nothing
                print("File does not exist")
                return None